use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

type SpendDatum {
  policy_id: ByteArray,
}

validator oracle_spend {
  spend(
    datum: Option<SpendDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let oracle_ref_input =
      list.find(
        self.reference_inputs,
        fn(inp) {
          list.any(
            assets.policies(inp.output.value),
            fn(pol) { pol == d.policy_id },
          )
        },
      )
    expect Some(ref_input) = oracle_ref_input
    expect InlineDatum(raw_datum) = ref_input.output.datum
    expect oracle_price: Int = raw_datum
    oracle_price > 0
  }
}

