use aiken/collection/list
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

type MultisigDatum {
  required_signers: List<ByteArray>,
  threshold: Int,
}

validator multisig_threshold {
  spend(
    datum: Option<MultisigDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let sig_count =
          list.count(
            d.required_signers,
            fn(s) { list.has(self.extra_signatories, s) },
          )
        sig_count >= d.threshold
      }
    }
  }
}
